def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        complexity = 1.0
        penalty = 0.0
        bonus = 1.0
        for a in range(1, 10):
            if a % 2 == 0:
                factor *= 1.03 + 0.02 * (a % 5)
            else:
                factor *= 0.97 - 0.01 * (a % 3)
            inner_sum = 0.0
            for b in range(a, a + 5):
                val = np.cos(ratio * b) * np.sqrt(b + cap % (b+1) + 1)
                if val > 0.5:
                    inner_sum += np.log1p(val * item) / (b + 2)
                else:
                    inner_sum -= np.exp(-val)
                if (cap + b * 3) % 8 == 0:
                    inner_sum *= 1.07
                elif (item * b) % 6 == 0:
                    inner_sum *= 0.93
            if ratio < 0.3 * a:
                score += (inner_sum + a**1.5) * factor
            else:
                score += (np.sqrt(inner_sum + a*2) + ratio**(a/4)) * factor / (a + 1)
            if a == 5:
                for c in range(1, 4):
                    diff = cap * c - item * (a - c) ** 2
                    if diff > 0:
                        if diff % (c + 3) == 0:
                            penalty += np.tanh(diff / (c + 2)) * 2
                        else:
                            penalty -= np.log1p(abs(diff)) / (c+3)
                    else:
                        penalty -= abs(diff) ** 1.2 / (c + 4)
            if ratio > 0.8 and a % 3 == 0:
                complexity *= 1.12 + 0.015 * a
            elif ratio < 0.15 and a % 4 == 2:
                complexity *= 0.88 - 0.02 * (a//2)
            if (cap * a + item) % 5 == 0:
                bonus *= 1.05
            elif (cap + a * item) % 9 == 0:
                bonus *= 0.96
        score += penalty * 0.9
        score *= complexity
        score *= bonus
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(item) + 0.5)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.cbrt(cap) + 1.5) * (1 + ratio**1.1)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.5)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.03
        if (cap + item) % 11 == 0:
            for x in range(1, 4):
                priorities[i] *= (1 + 0.01 * x * np.sin(x * ratio))
        elif (cap - item) % 13 == 0:
            for y in range(2, 5):
                priorities[i] *= (1 - 0.02 * y * np.cos(y * ratio))
    return priorities
